-- Ejecutar DESPUÉS de seed_academias_jefes.sql
-- Borra ETS existentes de ISC e IIA y los recrea correctamente.
--
-- Jefes por academia (ya creados en seed_academias_jefes.sql):
--   MAT  = b1b10000-...   CIRC = b2b20000-...   PROG = b3b30000-...
--   SOC  = b4b40000-...   SIST = b5b50000-...   IA   = b6b60000-...
-- ============================================================

-- ── Limpiar ETS previos de ISC e IIA ──────────────────────────────────────
DELETE FROM ets WHERE id_carrera_materia IN (
  SELECT id_carrera_materia FROM carrera_materia
  WHERE id_carrera IN (
    '609ff2de-7bc7-4288-bb40-925af48df292',  -- ISC
    '86f05125-991a-4a46-8a42-d17b299c807e'   -- IIA
  )
);

