-- ── Verificación ───────────────────────────────────────────────────────────
SELECT c.acronimo, m.nombre AS materia, a.acronimo AS academia, COUNT(*) AS ets_count
FROM ets e
JOIN carrera_materia cm ON cm.id_carrera_materia = e.id_carrera_materia
JOIN carrera c ON c.id_carrera = cm.id_carrera
JOIN materia m ON m.id_materia = cm.id_materia
JOIN academia a ON a.id_academia = cm.id_academia
WHERE c.acronimo IN ('ISC','IIA')
GROUP BY c.acronimo, m.nombre, a.acronimo
ORDER BY c.acronimo, a.acronimo, m.nombre;
